<div class="page-title-row"><div><p class="text-muted mb-1">Automation & communications</p><h1>Notification Routing</h1></div></div>
<div class="row g-4"><div class="col-xl-5"><section class="portal-card"><h2>Add route</h2><form method="post" action="/portal/notification-routes" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Event key</label><input class="form-control" name="event_key" placeholder="corrective_action.overdue" required></div><div class="col-md-6"><label class="form-label">Channel</label><select class="form-select" name="channel"><option>portal</option><option>email</option><option>teams</option><option>sms</option></select></div><div class="col-md-6"><label class="form-label">Minimum severity</label><select class="form-select" name="severity_min"><option>info</option><option>warning</option><option>critical</option></select></div><div class="col-md-5"><label class="form-label">Recipient type</label><select class="form-select" name="recipient_type"><option>role</option><option>user</option><option>email</option><option>phone</option><option>teams_webhook</option></select></div><div class="col-md-7"><label class="form-label">Recipient</label><input class="form-control" name="recipient_value" placeholder="owner or address" required></div><div class="col-12 form-check ms-2"><input class="form-check-input" type="checkbox" name="active" checked id="routeActive"><label class="form-check-label" for="routeActive">Active</label></div><div class="col-12"><button class="btn btn-primary">Save route</button></div></form></section></div><div class="col-xl-7"><section class="portal-card"><h2>Configured routes</h2><div class="table-responsive"><table class="table portal-table"><thead><tr><th>Event</th><th>Channel</th><th>Recipient</th><th>Severity</th><th></th></tr></thead><tbody><?php foreach($routes as $route):?><tr><td><?=e($route['event_key'])?></td><td><?=e($route['channel'])?></td><td><small><?=e($route['recipient_type'])?></small><?=e($route['recipient_value'])?></td><td><?=e($route['severity_min'])?></td><td><form method="post" action="/portal/notification-routes/<?=$route['id']?>/delete"><?=csrf_field()?><button class="btn btn-sm btn-outline-danger"><i class="fa-solid fa-trash"></i></button></form></td></tr><?php endforeach?><tr class="<?=count($routes)?'d-none':''?>"><td colspan="5" class="text-muted">No routing rules yet.</td></tr></tbody></table></div></section></div></div>
<div class="row g-4 mt-1"><div class="col-xl-4"><section class="portal-card"><h2>Test routing</h2><form method="post" action="/portal/notification-routes/test" class="row g-3"><?=csrf_field()?><div class="col-12"><label class="form-label">Event key</label><input class="form-control" name="event_key" value="system.test"></div><div class="col-12"><label class="form-label">Severity</label><select class="form-select" name="severity"><option>info</option><option>warning</option><option>critical</option></select></div><div class="col-12"><label class="form-label">Message</label><textarea class="form-control" name="message">This is a notification-routing test.</textarea></div><div class="col-12"><button class="btn btn-primary">Run test</button></div></form></section></div><div class="col-xl-8"><section class="portal-card"><h2>Recent deliveries</h2><div class="table-responsive"><table class="table portal-table"><thead><tr><th>Time</th><th>Event</th><th>Channel</th><th>Recipient</th><th>Status</th></tr></thead><tbody><?php foreach(($logs??[]) as $log):?><tr><td><?=e($log['created_at'])?></td><td><?=e($log['event_key'])?></td><td><?=e($log['channel'])?></td><td><?=e($log['recipient'])?></td><td><span class="badge text-bg-<?=$log['status']==='sent'?'success':($log['status']==='failed'?'danger':'secondary')?>"><?=e($log['status'])?></span><?php if($log['error_message']):?><div class="small text-danger"><?=e($log['error_message'])?></div><?php endif?></td></tr><?php endforeach?><?php if(empty($logs)):?><tr><td colspan="5" class="text-muted text-center">No deliveries recorded.</td></tr><?php endif?></tbody></table></div></section></div></div>
